import{_ as a,o,c as t,a3 as n}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Namespace clore::agent","description":"clore::agent 命名空间封装了代理系统的核心机制，负责驱动基于工具调用的自动化代码探索与文档生成流程。其显著声明包括高层入口函数 run_agent 和 run_agent_async，前者同步运行代理循环并返回生成的文档数量（成功时以 std::size_t 表示，失败时以 AgentError 表示），后者在 kota::event_loop 上启动异步操作。此外，build_tool_definitions 提供工具定义集合的初始化入口，dispatch_tool_call 是工具调度的核心函数，依据工具名称和参数执行并返回结果或 ToolError，而 extract_string_arg 则负责从 JSON 参数中安全提取字符串值。ToolError 和 AgentError 结构体用于表达工具调用或代理运行过程中的特定错误。","frontmatter":{"title":"Namespace clore::agent","description":"clore::agent 命名空间封装了代理系统的核心机制，负责驱动基于工具调用的自动化代码探索与文档生成流程。其显著声明包括高层入口函数 run_agent 和 run_agent_async，前者同步运行代理循环并返回生成的文档数量（成功时以 std::size_t 表示，失败时以 AgentError 表示），后者在 kota::event_loop 上启动异步操作。此外，build_tool_definitions 提供工具定义集合的初始化入口，dispatch_tool_call 是工具调度的核心函数，依据工具名称和参数执行并返回结果或 ToolError，而 extract_string_arg 则负责从 JSON 参数中安全提取字符串值。ToolError 和 AgentError 结构体用于表达工具调用或代理运行过程中的特定错误。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/agent/index.md","filePath":"zh/clore/namespaces/clore/agent/index.md"}'),r={name:"zh/clore/namespaces/clore/agent/index.md"};function c(l,e,d,i,s,p){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="namespace-clore-agent" tabindex="-1">Namespace <code>clore::agent</code> <a class="header-anchor" href="#namespace-clore-agent" aria-label="Permalink to &quot;Namespace `clore::agent`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::agent</code> 命名空间封装了代理系统的核心机制，负责驱动基于工具调用的自动化代码探索与文档生成流程。其显著声明包括高层入口函数 <code>run_agent</code> 和 <code>run_agent_async</code>，前者同步运行代理循环并返回生成的文档数量（成功时以 <code>std::size_t</code> 表示，失败时以 <code>AgentError</code> 表示），后者在 <code>kota::event_loop</code> 上启动异步操作。此外，<code>build_tool_definitions</code> 提供工具定义集合的初始化入口，<code>dispatch_tool_call</code> 是工具调度的核心函数，依据工具名称和参数执行并返回结果或 <code>ToolError</code>，而 <code>extract_string_arg</code> 则负责从 JSON 参数中安全提取字符串值。<code>ToolError</code> 和 <code>AgentError</code> 结构体用于表达工具调用或代理运行过程中的特定错误。</p><p>该命名空间在架构中扮演代理系统的中枢角色，协调 LLM 模型、工具补全缓存、输出根目录及会话状态等组件。其内部的变量（如 <code>model</code>、<code>arguments</code>、<code>output_root</code>、<code>config</code>、<code>cache</code> 等）反映了代理运行时的关键上下文。通过 <code>dispatch_tool_call</code> 和 <code>build_tool_definitions</code> 等函数，它实现了工具调度层与代理控制逻辑的解耦，使上层应用能够专注于任务定义和结果处理，而无需直接操作底层工具执行细节。</p><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-agent-agenterror" tabindex="-1"><code>clore::agent::AgentError</code> <a class="header-anchor" href="#clore-agent-agenterror" aria-label="Permalink to &quot;`clore::agent::AgentError`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:21</code></p><p>Definition: <code>agent/agent.cppm:21</code></p><p>Implementation: <a href="./../../../modules/agent/"><code>Module agent</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>message should contain a non-empty string describing the error context</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li>message</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>returned as an error type from agent operations</li><li>used to propagate error information via exceptions or result types</li></ul><h3 id="clore-agent-toolerror" tabindex="-1"><code>clore::agent::ToolError</code> <a class="header-anchor" href="#clore-agent-toolerror" aria-label="Permalink to &quot;`clore::agent::ToolError`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:16</code></p><p>Definition: <code>agent/tools.cppm:16</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-agent-build-tool-definitions" tabindex="-1"><code>clore::agent::build_tool_definitions</code> <a class="header-anchor" href="#clore-agent-build-tool-definitions" aria-label="Permalink to &quot;`clore::agent::build_tool_definitions`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:23</code></p><p>Definition: <code>agent/tools.cppm:887</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p><code>clore::agent::build_tool_definitions</code> 为调用者提供构建工具定义集合的入口点。该函数不接收任何参数，返回一个 <code>int</code> 值，用于指示操作结果或定义的数量。调用者应在需要初始化或更新工具定义列表时调用此函数；返回值的具体含义（例如成功状态码或定义计数）由调用者根据契约进行解释。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to prepare tool definitions for a chat API request</li><li>used in agent initialization</li></ul><h3 id="clore-agent-dispatch-tool-call" tabindex="-1"><code>clore::agent::dispatch_tool_call</code> <a class="header-anchor" href="#clore-agent-dispatch-tool-call" aria-label="Permalink to &quot;`clore::agent::dispatch_tool_call`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:26</code></p><p>Definition: <code>agent/tools.cppm:902</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p><code>clore::agent::dispatch_tool_call</code> 是工具调度系统的核心入口，负责根据指定的工具名称和参数执行工具调用。调用者需提供工具名称、参数 JSON 值、会话标识符以及客户端和请求标识符。函数返回 <code>std::expected&lt;std::string, ToolError&gt;</code>，成功时包含工具执行的字符串结果，失败时包含详细的错误信息。调用者应始终检查返回值，并在出错时采取适当措施（例如向用户报告错误）。该函数不会直接修改会话状态，但执行结果可能影响后续代理步骤。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to handle tool execution requests</li><li>Used by agent loop to dispatch tool calls</li></ul><h3 id="clore-agent-extract-string-arg" tabindex="-1"><code>clore::agent::extract_string_arg</code> <a class="header-anchor" href="#clore-agent-extract-string-arg" aria-label="Permalink to &quot;`clore::agent::extract_string_arg`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:20</code></p><p>Definition: <code>agent/tools.cppm:865</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p>从给定的 <code>json::Value</code> 对象中提取由名称标识的字符串参数。如果名称对应的参数不存在或其值不是字符串类型，则返回一个表示失败的 <code>ToolError</code>。该函数是工具调用参数提取的核心契约，确保调用方获得一个经过验证的字符串值或明确的错误原因。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>dispatch_tool_call</code> to extract required string arguments from tool invocation JSON</li></ul><h3 id="clore-agent-run-agent" tabindex="-1"><code>clore::agent::run_agent</code> <a class="header-anchor" href="#clore-agent-run-agent" aria-label="Permalink to &quot;`clore::agent::run_agent`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:27</code></p><p>Definition: <code>agent/agent.cppm:524</code></p><p>Implementation: <a href="./../../../modules/agent/"><code>Module agent</code></a></p><p>函数 <code>clore::agent::run_agent</code> 负责运行代理循环：通过工具调用探索代码库，并在输出根目录下的 <code>guides/</code> 夹中生成指南文档。调用者需提供两个整数引用（<code>const int &amp;</code>）、一个字符串视图（<code>std::string_view</code>，通常指向输出根目录路径）及一个字符串（<code>std::string</code>）。成功时该函数返回生成的文档数量（<code>std::size_t</code>），失败时返回 <code>AgentError</code>。调用者应检查 <code>std::expected</code> 的返回状态以处理潜在错误。</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to execute the full agent workflow synchronously from user-facing entry points</li><li>Wraps the asynchronous <code>run_agent_async</code> in an event loop for blocking invocation</li></ul><h3 id="clore-agent-run-agent-async" tabindex="-1"><code>clore::agent::run_agent_async</code> <a class="header-anchor" href="#clore-agent-run-agent-async" aria-label="Permalink to &quot;`clore::agent::run_agent_async`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:34</code></p><p>Definition: <code>agent/agent.cppm:507</code></p><p>Implementation: <a href="./../../../modules/agent/"><code>Module agent</code></a></p><p><code>clore::agent::run_agent_async</code> 启动一个异步代理循环，在给定的 <code>kota::event_loop</code> 上运行。调用者必须将返回的任务调度到该循环上并执行它。该函数接受两个 <code>const int &amp;</code> 参数、两个 <code>std::string</code> 参数以及一个 <code>kota::event_loop &amp;</code> 引用，返回一个 <code>int</code> 值，代表异步操作的结果或状态。</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Launch asynchronous agent with event loop</li><li>Wrap synchronous agent with cache loading</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore</a></li></ul>',59)])])}const h=a(r,[["render",c]]);export{u as __pageData,h as default};
